/**
 * Scroll Module
 * Handles GSAP Observer, scroll events, direction-aware interruption, and section navigation
 */
(function() {
  'use strict';
  
  // Initialize Portfolio namespace
  window.Portfolio = window.Portfolio || {};
  
  // Module-level variables
  let observer = null;
  let animationState = {
    currentDirection: 0, // -1 = up, 1 = down, 0 = none
    scrollTween: null, // Track the main scroll tween for interruption
    pendingCallbacks: [] // Track all pending GSAP delayed calls
  };
  
  let scrollQueue = {
    pending: null,
    timeout: null,
    debounceDelay: 100 // 100ms debounce
  };
  
  /**
   * Setup GSAP scroll observer with direction-aware interruption
   */
  function setupScrollObserver(CONFIG) {
    // Kill existing observer if it exists
    if (observer) observer.kill();
    
    observer = Observer.create({
      target: window,
      type: "wheel,touch,pointer",
      wheelSpeed: CONFIG.navigation.wheelSpeed,
      preventDefault: true,
      dragMinimum: 250,
      tolerance: 10, // Small tolerance to prevent over-sensitivity
      lockAxis: true,
      
      onUp: () => {
        handleScrollEvent(-1, CONFIG); // Up direction
      },
      
      onDown: () => {
        handleScrollEvent(1, CONFIG); // Down direction
      }
    });
  }
  
  /**
   * Handle scroll events with direction-aware interruption logic
   */
  function handleScrollEvent(direction, CONFIG) {
    if (CONFIG.debug) {
      console.log(`[SCROLL] Direction: ${direction}, IsAnimating: ${window.isAnimating}, CurrentDirection: ${animationState.currentDirection}, CurrentSection: ${window.currentSection}`);
    }
    
    if (window.isAnimating) {
      // Check if this is opposite direction to current animation
      if (animationState.currentDirection !== 0 && direction !== animationState.currentDirection) {
        // Opposite direction - interrupt and reverse!
        if (CONFIG.debug) {
          console.log(`[INTERRUPT] Opposite direction detected! Current: ${animationState.currentDirection}, New: ${direction}`);
        }
        interruptAndReverse(direction, CONFIG);
        return;
      } else {
        // Same direction - ignore (let current animation complete)
        if (CONFIG.debug) {
          console.log(`[IGNORE] Same direction scroll ignored during animation`);
        }
        return;
      }
    }
    
    // Normal scroll handling when not animating
    if (direction === -1 && window.currentSection > 0) {
      queueScrollDirection(-1);
    } else if (direction === 1 && window.currentSection < window.sectionCount - 1) {
      queueScrollDirection(1);
    }
  }
  
  /**
   * Interrupt current animation and reverse direction smoothly
   */
  function interruptAndReverse(newDirection, CONFIG) {
    // Calculate target section for reverse direction from CURRENT position
    const targetSection = window.currentSection + newDirection;
    
    // Validate target section
    if (targetSection < 0 || targetSection >= window.sectionCount) return;
    
    // Kill current scroll tween if it exists
    if (animationState.scrollTween) {
      animationState.scrollTween.kill();
      animationState.scrollTween = null;
    }
    
    // Clear any pending scroll queue
    if (scrollQueue.timeout) {
      clearTimeout(scrollQueue.timeout);
      scrollQueue.timeout = null;
      scrollQueue.pending = null;
    }
    
    // TARGETED CLEANUP: Only kill specific animations, not everything
    const currentSectionElement = window.sections[window.currentSection];
    if (currentSectionElement) {
      const elementsToStop = currentSectionElement.querySelectorAll('*');
      gsap.killTweensOf(elementsToStop);
    }
    
    // CANCEL ALL PENDING DELAYED CALLS that could add headers
    animationState.pendingCallbacks.forEach(callback => {
      if (callback) callback.kill();
    });
    animationState.pendingCallbacks = [];
    
    // ALWAYS do aggressive header cleanup during interruptions
    if (window.Portfolio.ui && window.Portfolio.ui.clearAllHeaderTitles) {
      window.Portfolio.ui.clearAllHeaderTitles();
    }
    
    // EXTRA AGGRESSIVE header cleanup for banner target
    if (targetSection === 0) {
      // Force immediate header cleanup again
      setTimeout(() => {
        if (window.Portfolio.ui && window.Portfolio.ui.clearAllHeaderTitles) {
          window.Portfolio.ui.clearAllHeaderTitles();
        }
      }, 5);
      setTimeout(() => {
        if (window.Portfolio.ui && window.Portfolio.ui.clearAllHeaderTitles) {
          window.Portfolio.ui.clearAllHeaderTitles();
        }
      }, 20);
      
      if (CONFIG.debug) {
        console.log('[INTERRUPT] Extra aggressive header cleanup for banner target');
      }
      
      // Force banner state immediately
      document.body.classList.add('banner-active');
    }
    
    // Reset animation state immediately
    animationState.currentDirection = 0;
    window.isAnimating = false;
    
    // Start immediate reverse animation from current position
    setTimeout(() => {
      goToSection(targetSection, true, CONFIG); // true = isInterrupting
    }, 10); // Small delay to ensure clean state reset
  }
  
  /**
   * Queue scroll direction with debouncing
   */
  function queueScrollDirection(direction) {
    // If already animating, ignore
    if (window.isAnimating) return;
    
    // Clear existing timeout
    if (scrollQueue.timeout) {
      clearTimeout(scrollQueue.timeout);
    }
    
    // Set the latest direction
    scrollQueue.pending = direction;
    
    // Execute after debounce delay
    scrollQueue.timeout = setTimeout(() => {
      if (scrollQueue.pending !== null && !window.isAnimating) {
        const targetSection = window.currentSection + scrollQueue.pending;
        if (targetSection >= 0 && targetSection < window.sectionCount) {
          goToSection(targetSection, false, window.CONFIG);
        }
        scrollQueue.pending = null;
        scrollQueue.timeout = null;
      }
    }, scrollQueue.debounceDelay);
  }
  
  /**
   * Navigate to a specific section
   */
  function goToSection(index, isInterrupting = false, CONFIG) {
    // Validate index
    index = Math.max(0, Math.min(index, window.sectionCount - 1));
    if (index === window.currentSection && !isInterrupting) return;
    
    // Hide scroll buttons immediately when animation starts
    if (window.Portfolio.ui && window.Portfolio.ui.hideScrollButtons) {
      window.Portfolio.ui.hideScrollButtons();
    }
    
    // Set animation lock but KEEP observer enabled for interruption detection
    window.isAnimating = true;
    // DO NOT disable observer - we need it for opposite direction detection!
    
    // Track animation direction
    const direction = index > window.currentSection ? 1 : -1;
    animationState.currentDirection = direction;
    
    // Clear any pending scroll queue
    if (scrollQueue.timeout) {
      clearTimeout(scrollQueue.timeout);
      scrollQueue.timeout = null;
      scrollQueue.pending = null;
    }
    
    // Store section references
    const prevIndex = window.currentSection;
    const prevSection = window.sections[prevIndex];
    const targetSection = window.sections[index];
    window.currentSection = index;
    
    // Update navigation immediately
    if (window.Portfolio.navigation && window.Portfolio.navigation.updateNavigation) {
      window.Portfolio.navigation.updateNavigation(index, false, CONFIG);
    }
    
    // Check if target is banner
    const isBanner = index === 0;
    
    // Update body class for banner
    document.body.classList.toggle('banner-active', isBanner);
    
    // IMMEDIATE banner reset if targeting banner - don't wait for callback
    if (isBanner) {
      const bannerSection = document.getElementById('banner');
      if (bannerSection && window.resetBannerContent) {
        window.resetBannerContent(bannerSection);
        if (CONFIG.debug) {
          console.log('[BANNER] Immediate banner reset applied');
        }
      }
    }
    
    // Handle glass container
    if (isBanner) {
      const glassContainer = document.querySelector('.section-glass-container');
      if (glassContainer) {
        gsap.set(glassContainer, {
          opacity: 0,
          visibility: "hidden",
          display: "none",
          scale: 0
        });
      }
    } else {
      if (window.Portfolio.ui && window.Portfolio.ui.updateGlassContainer) {
        window.Portfolio.ui.updateGlassContainer(targetSection, true);
      }
    }
    
    // Handle header title - ALWAYS call this to clear stacked titles
    if (window.Portfolio.ui && window.Portfolio.ui.updateHeaderTitle) {
      window.Portfolio.ui.updateHeaderTitle(prevIndex, index);
    }
    
    // Scroll to target position
    const targetY = index * window.innerHeight;
    
    // Create scroll tween and track it for potential interruption
    animationState.scrollTween = gsap.to(window, {
      scrollTo: { y: targetY, autoKill: false },
      duration: 0.01,
      ease: 'none',
      onComplete: () => {
        // Clear scroll tween reference
        animationState.scrollTween = null;
        
        // Exit animation for previous section - BUT NOT if going to banner
        if (prevSection && !isBanner && window.animateSectionContent) {
          window.animateSectionContent(prevSection, false);
        } else if (isBanner && CONFIG.debug) {
          console.log('[BANNER] Skipping exit animation when going to banner');
        }
        
        // Entry animation for target section (with small delay)
        gsap.delayedCall(CONFIG.animation.fadeSpeed * 0.1, () => {
          if (isBanner) {
            const bannerSection = document.getElementById('banner');
            if (bannerSection && window.animateBannerContent) {
              // Banner already reset immediately, just animate
              if (CONFIG.debug) {
                console.log('[BANNER] Starting banner animation');
              }
              window.animateBannerContent(bannerSection, isInterrupting);
            }
          } else {
            if (window.animateSectionContent) {
              window.animateSectionContent(targetSection, true);
            }
          }
        });
        
        // Final actions after animation completes
        const finalCallback = gsap.delayedCall(CONFIG.animation.duration * 1.2, () => {
          if (window.Portfolio.ui && window.Portfolio.ui.updateScrollButtons) {
            window.Portfolio.ui.updateScrollButtons(); // Show buttons after animation completes
          }
          if (window.Portfolio.ui && window.Portfolio.ui.addHeaderTitle) {
            window.Portfolio.ui.addHeaderTitle(index);
          }
          
          // Reset animation state - Observer stays enabled!
          animationState.currentDirection = 0;
          window.isAnimating = false;
          
          // Remove this callback from tracking
          const callbackIndex = animationState.pendingCallbacks.indexOf(finalCallback);
          if (callbackIndex > -1) {
            animationState.pendingCallbacks.splice(callbackIndex, 1);
          }
          
          if (CONFIG.debug && window.logDebugInfo) {
            window.logDebugInfo(`Navigated to section ${index}`);
          }
        });
        
        // Track the callback so it can be cancelled during interruptions
        animationState.pendingCallbacks.push(finalCallback);
      }
    });
  }
  
  // Expose scroll functions
  window.Portfolio.scroll = {
    setupScrollObserver,
    handleScrollEvent,
    interruptAndReverse,
    queueScrollDirection,
    goToSection,
    // Expose state for other modules
    getAnimationState: () => animationState,
    getScrollQueue: () => scrollQueue
  };
  
  if (window.Portfolio.debug) {
    console.log('[SCROLL] Module loaded successfully');
  }
})(); 